```class Solution {
public:
    bool haveConflict(vector<string>& event1, vector<string>& event2) {
        for (int i = 0; i < event1.size(); i++) {
            int start1 = stoi(event1[i].substr(0, 2));
            int end1 = stoi(event1[i].substr(event1[i].length() - 2));
            int start2 = stoi(event2[i].substr(0, 2));
            int end2 = stoi(event2[i].substr(event2[i].length() - 2));

            if (start1 <= end2 && end1 >= start2) {
                return true;
            }
        }
        return false;
    }
};
```

